import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicMixedArray() {
        // [1,1,0,0,1,1,1,0,1] k=2: flip zeros at idx 2 and 3 → window of length 7
        assertEquals(7, new Solution().longestOnes(
                new int[]{1, 1, 0, 0, 1, 1, 1, 0, 1}, 2));
    }

    @Test
    void allOnesKZero() {
        // No zeros to flip, already a run of 3 ones
        assertEquals(3, new Solution().longestOnes(new int[]{1, 1, 1}, 0));
    }

    @Test
    void allZerosKTwo() {
        // [0,0,0] k=2: can cover at most 2 zeros → length 2
        assertEquals(2, new Solution().longestOnes(new int[]{0, 0, 0}, 2));
    }

    @Test
    void emptyArray() {
        // Empty input must return 0
        assertEquals(0, new Solution().longestOnes(new int[]{}, 3));
    }

    @Test
    void allZerosKZero() {
        // k=0 and all zeros: no valid window of length > 0
        assertEquals(0, new Solution().longestOnes(new int[]{0, 0, 0, 0}, 0));
    }

    @Test
    void kLargerThanZeroCount() {
        // More flips available than there are zeros — entire array is valid
        assertEquals(6, new Solution().longestOnes(new int[]{1, 0, 1, 1, 0, 1}, 5));
    }

    @Test
    void adversarialAlternating() {
        // [0,1,0,1,0] k=1: best window is any triplet with one zero, length 3
        assertEquals(3, new Solution().longestOnes(new int[]{0, 1, 0, 1, 0}, 1));
    }
}
